//! About-panel gesture. A short directional sequence on the about screen
//! reveals a small acknowledgements panel - a piece of art plus a few lines of
//! text. The step pattern and the panel resources are stored packed and
//! expanded on demand so they don't sit in the source as bulky literals.

use axum::{http::StatusCode, Json};
use base64::{engine::general_purpose::STANDARD, Engine as _};
use serde::{Deserialize, Serialize};
use std::sync::{LazyLock, Mutex};
use std::time::{Duration, Instant};

const BLEND: u8 = 0x5A;
const RESET_AFTER: Duration = Duration::from_secs(6);
const STEP_LEN: usize = 12;
const STEP_TABLE: [u8; STEP_LEN] = [90, 91, 88, 89, 90, 91, 88, 89, 90, 91, 88, 89];
const GRADIENT_MAP: &str =
    "";
const GLYPH_ATLAS: &str =
    "";

#[derive(Serialize)]
pub struct HalcyonResponse {
    pub unlocked: bool,
    pub message: Option<String>,
    pub mark: Option<String>,
}

#[derive(Default)]
struct HalcyonState {
    cursor: usize,
    last_input: Option<Instant>,
}

static HALCYON_STATE: LazyLock<Mutex<HalcyonState>> =
    LazyLock::new(|| Mutex::new(HalcyonState::default()));

pub fn halcyon_reset() -> Result<(), String> {
    let mut state = HALCYON_STATE
        .lock()
        .map_err(|_| "Internal sequence state error".to_string())?;
    *state = HalcyonState::default();
    Ok(())
}

pub fn halcyon_probe(direction_code: u8) -> Result<HalcyonResponse, String> {
    if direction_code > 3 {
        return Err("Unsupported direction code".to_string());
    }

    let mut state = HALCYON_STATE
        .lock()
        .map_err(|_| "Internal sequence state error".to_string())?;

    if let Some(last_input) = state.last_input {
        if last_input.elapsed() > RESET_AFTER {
            state.cursor = 0;
        }
    }
    state.last_input = Some(Instant::now());

    let expected = steps();
    let expected_next = expected.get(state.cursor).copied().unwrap_or(expected[0]);

    if direction_code == expected_next {
        state.cursor += 1;
        if state.cursor >= STEP_LEN {
            state.cursor = 0;
            return Ok(HalcyonResponse {
                unlocked: true,
                message: Some(inflate(GRADIENT_MAP)?),
                mark: Some(inflate(GLYPH_ATLAS)?),
            });
        }

        return Ok(HalcyonResponse {
            unlocked: false,
            message: None,
            mark: None,
        });
    }

    state.cursor = if direction_code == expected[0] { 1 } else { 0 };
    Ok(HalcyonResponse {
        unlocked: false,
        message: None,
        mark: None,
    })
}

fn steps() -> [u8; STEP_LEN] {
    let mut out = [0u8; STEP_LEN];
    let mut idx = 0usize;
    while idx < STEP_LEN {
        out[idx] = STEP_TABLE[idx] ^ BLEND;
        idx += 1;
    }
    out
}

fn inflate(data: &str) -> Result<String, String> {
    let raw = STANDARD
        .decode(data.as_bytes())
        .map_err(|error| format!("Cannot read resource: {error}"))?;

    let bytes = raw
        .into_iter()
        .map(|value| value ^ BLEND)
        .collect::<Vec<u8>>();

    String::from_utf8(bytes).map_err(|error| format!("Invalid resource: {error}"))
}

#[derive(Deserialize)]
pub struct SampleInput {
    pub direction_code: u8,
}

pub async fn ui_metric_sample(Json(input): Json<SampleInput>) -> Json<HalcyonResponse> {
    match halcyon_probe(input.direction_code) {
        Ok(response) => Json(response),
        Err(_) => Json(HalcyonResponse {
            unlocked: false,
            message: None,
            mark: None,
        }),
    }
}

pub async fn ui_metric_reset() -> StatusCode {
    let _ = halcyon_reset();
    StatusCode::NO_CONTENT
}
